SET sql_mode = 'NO_AUTO_VALUE_ON_ZERO';
START TRANSACTION;
SET time_zone = '+00:00';
SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS `migrations`;
CREATE TABLE `migrations` (`id` integer primary key AUTO_INCREMENT not null, `migration` VARCHAR(255) not null, `batch` integer not null);


DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (`id` integer primary key AUTO_INCREMENT not null, `name` VARCHAR(255) not null, `email` VARCHAR(255) not null, `email_verified_at` datetime, `password` VARCHAR(255) not null, `remember_token` VARCHAR(255), `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `password_reset_tokens`;
CREATE TABLE `password_reset_tokens` (`email` VARCHAR(255) not null, `token` VARCHAR(255) not null, `created_at` datetime, primary key (`email`));


DROP TABLE IF EXISTS `sessions`;
CREATE TABLE `sessions` (`id` VARCHAR(255) not null, `user_id` integer, `ip_address` VARCHAR(255), `user_agent` text, `payload` text not null, `last_activity` integer not null, primary key (`id`));


DROP TABLE IF EXISTS `cache`;
CREATE TABLE `cache` (`key` VARCHAR(255) not null, `value` text not null, `expiration` integer not null, primary key (`key`));


DROP TABLE IF EXISTS `cache_locks`;
CREATE TABLE `cache_locks` (`key` VARCHAR(255) not null, `owner` VARCHAR(255) not null, `expiration` integer not null, primary key (`key`));


DROP TABLE IF EXISTS `jobs`;
CREATE TABLE `jobs` (`id` integer primary key AUTO_INCREMENT not null, `queue` VARCHAR(255) not null, `payload` text not null, `attempts` integer not null, `reserved_at` integer, `available_at` integer not null, `created_at` integer not null);


DROP TABLE IF EXISTS `job_batches`;
CREATE TABLE `job_batches` (`id` VARCHAR(255) not null, `name` VARCHAR(255) not null, `total_jobs` integer not null, `pending_jobs` integer not null, `failed_jobs` integer not null, `failed_job_ids` text not null, `options` text, `cancelled_at` integer, `created_at` integer not null, `finished_at` integer, primary key (`id`));


DROP TABLE IF EXISTS `failed_jobs`;
CREATE TABLE `failed_jobs` (`id` integer primary key AUTO_INCREMENT not null, `uuid` VARCHAR(255) not null, `connection` text not null, `queue` text not null, `payload` text not null, `exception` text not null, `failed_at` datetime not null default CURRENT_TIMESTAMP);


DROP TABLE IF EXISTS `sertifikat_kematian_dewasas`;
CREATE TABLE `sertifikat_kematian_dewasas` (`id` integer primary key AUTO_INCREMENT not null, `nik` VARCHAR(255) not null, `nama_lengkap` VARCHAR(255) not null, `jenis_kelamin` VARCHAR(255) not null, `tempat_lahir` VARCHAR(255) not null, `tanggal_lahir` date not null, `pekerjaan` VARCHAR(255), `waktu_meninggal` datetime not null, `usia` integer not null, `penyebab_langsung` VARCHAR(255), `interval_langsung` VARCHAR(255), `penyebab_antara` VARCHAR(255), `interval_antara` VARCHAR(255), `penyebab_dasar` VARCHAR(255), `interval_dasar` VARCHAR(255), `penyebab_utama` VARCHAR(255), `interval_utama` VARCHAR(255), `nama_dokter` VARCHAR(255) not null, `nomor_sip` VARCHAR(255) not null, `tanda_tangan` VARCHAR(255) not null, `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `patients`;
CREATE TABLE `patients` (`id` integer primary key AUTO_INCREMENT not null, `nrm` VARCHAR(255) not null, `nik` VARCHAR(255), `nama_lengkap` VARCHAR(255) not null, `jenis_kelamin` VARCHAR(255) not null, `tempat_lahir` VARCHAR(255), `tanggal_lahir` date, `pekerjaan` VARCHAR(255), `alamat` text, `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `certificates`;
CREATE TABLE `certificates` (`id` integer primary key AUTO_INCREMENT not null, `nomor_sertifikat` VARCHAR(255) not null, `jenis` VARCHAR(255) not null, `patient_id` integer not null, `doctor_id` integer not null, `waktu_meninggal` datetime not null, `status` VARCHAR(255) not null default 'Draft', `data` text, `created_at` datetime, `updated_at` datetime, foreign key(`patient_id`) references `patients`(`id`) on delete cascade, foreign key(`doctor_id`) references `doctors`(`id`) on delete cascade);


DROP TABLE IF EXISTS `activity_logs`;
CREATE TABLE `activity_logs` (`id` integer primary key AUTO_INCREMENT not null, `activity` VARCHAR(255) not null, `description` text, `ip_address` VARCHAR(255), `user_agent` VARCHAR(255), `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications` (`id` integer primary key AUTO_INCREMENT not null, `judul` VARCHAR(255) not null, `keterangan` text not null, `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `ip_trackers`;
CREATE TABLE `ip_trackers` (`id` integer primary key AUTO_INCREMENT not null, `ip_address` VARCHAR(255) not null, `name` VARCHAR(255), `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `doctors`;
CREATE TABLE `doctors` (`id` integer primary key AUTO_INCREMENT not null, `nama_dokter` VARCHAR(255) not null, `nomor_sip` VARCHAR(255), `spesialisasi` VARCHAR(255), `created_at` datetime, `updated_at` datetime);


SET FOREIGN_KEY_CHECKS = 1;
COMMIT;
